import { describe, expect, it } from "vite-plus/test";

import { cards, rawCards, structuredCards } from "../src/index.ts";

/**
 * Hand-rolled invariant checks over the autogenerated `cards` / `rawCards`
 * arrays in src/generated.ts and the hand-authored `structuredCards`. Catches
 * scraper drift and authoring drift that `satisfies CardDefinition[]` lets
 * through (TS structural typing accepts empty strings, malformed URLs, etc.).
 *
 * If/when zod or another schema validator is adopted, these can move to a
 * single schema definition. For now the explicit list keeps the dependency
 * graph small and the failure messages specific.
 */

const SLUG_REGEX = /^[a-z0-9-]+$/;
const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const KNOWN_SET_CODE_VALUES: ReadonlySet<string> = new Set([
  "alpha",
  "promo",
  "spoiler",
  "boxtoppersretail",
  "boxtoppersbeta",
  "embracingpowerbetastarterdeck",
  "embracingpowerretailstarterdeck",
  "theheistbetastarterdeck",
  "theheistretailstarterdeck",
  "welcometonightcitybeta",
  "welcometonightcityretail",
]);
const KNOWN_LEGALITIES: ReadonlySet<string> = new Set(["legal"]);
const KNOWN_COLORS: ReadonlySet<string> = new Set(["blue", "green", "red", "yellow"]);
const KNOWN_RAW_COLORS: ReadonlySet<string> = new Set(["Blue", "Green", "Red", "Yellow"]);
const KNOWN_CARD_TYPES: ReadonlySet<string> = new Set(["legend", "unit", "gear", "program"]);
const KNOWN_RAW_CARD_TYPES: ReadonlySet<string> = new Set(["Legend", "Unit", "Gear", "Program"]);

interface Violation {
  cardSlug: string;
  field: string;
  reason: string;
  value: unknown;
}

function assertString(
  source: string,
  field: string,
  value: unknown,
  violations: Violation[],
  opts: { regex?: RegExp; nonEmpty?: boolean; startsWith?: string } = {},
): void {
  if (typeof value !== "string") {
    violations.push({ cardSlug: source, field, reason: "not a string", value });
    return;
  }
  if (opts.nonEmpty !== false && value.length === 0) {
    violations.push({ cardSlug: source, field, reason: "empty string", value });
    return;
  }
  if (opts.regex && !opts.regex.test(value)) {
    violations.push({ cardSlug: source, field, reason: `does not match ${opts.regex}`, value });
  }
  if (opts.startsWith && !value.startsWith(opts.startsWith)) {
    violations.push({
      cardSlug: source,
      field,
      reason: `does not start with "${opts.startsWith}"`,
      value,
    });
  }
}

function assertEnum(
  source: string,
  field: string,
  value: unknown,
  enumSet: ReadonlySet<string>,
  violations: Violation[],
): void {
  if (typeof value !== "string" || !enumSet.has(value)) {
    violations.push({
      cardSlug: source,
      field,
      reason: `not a known value (allowed: ${[...enumSet].join(" | ")})`,
      value,
    });
  }
}

function assertExternalId(
  source: string,
  field: string,
  value: unknown,
  violations: Violation[],
): void {
  if (typeof value !== "string" || !/^(?:cyberpunk:|cb-)[a-z0-9-]+$/.test(value)) {
    violations.push({
      cardSlug: source,
      field,
      reason: 'does not start with "cyberpunk:" or "cb-"',
      value,
    });
  }
}

function assertNonNegativeIntOrNull(
  source: string,
  field: string,
  value: unknown,
  violations: Violation[],
): void {
  if (value === null || value === undefined) return;
  if (
    typeof value !== "number" ||
    !Number.isFinite(value) ||
    value < 0 ||
    !Number.isInteger(value)
  ) {
    violations.push({
      cardSlug: source,
      field,
      reason: "not a non-negative integer (or null)",
      value,
    });
  }
}

function assertNonNegativeInt(
  source: string,
  field: string,
  value: unknown,
  violations: Violation[],
): void {
  if (
    typeof value !== "number" ||
    !Number.isFinite(value) ||
    value < 0 ||
    !Number.isInteger(value)
  ) {
    violations.push({ cardSlug: source, field, reason: "not a non-negative integer", value });
  }
}

describe("card record invariants", () => {
  it("rawCards records all satisfy structural invariants", () => {
    const violations: Violation[] = [];
    for (const card of rawCards) {
      const slug = card.slug ?? "<missing slug>";
      assertString(slug, "id", card.id, violations, { regex: UUID_REGEX });
      assertExternalId(slug, "external_id", card.external_id, violations);
      assertString(slug, "slug", card.slug, violations, { regex: SLUG_REGEX });
      assertString(slug, "name", card.name, violations);
      assertString(slug, "display_name", card.display_name, violations);
      assertEnum(slug, "set.code", card.set?.code, KNOWN_SET_CODE_VALUES, violations);
      assertEnum(slug, "color", card.color, KNOWN_RAW_COLORS, violations);
      assertEnum(slug, "card_type", card.card_type, KNOWN_RAW_CARD_TYPES, violations);
      assertEnum(slug, "legality", card.legality, KNOWN_LEGALITIES, violations);
      assertString(slug, "image_url", card.image_url, violations, { startsWith: "https://" });
      assertString(slug, "source_image_url", card.source_image_url, violations, {
        startsWith: "https://",
      });
      assertString(slug, "print_number", card.print_number, violations);
      assertString(slug, "artist", card.artist, violations);
      assertNonNegativeInt(slug, "ram", card.ram, violations);
      assertNonNegativeIntOrNull(slug, "cost", card.cost, violations);
      assertNonNegativeIntOrNull(slug, "power", card.power, violations);
      if (!Array.isArray(card.classifications)) {
        violations.push({
          cardSlug: slug,
          field: "classifications",
          reason: "not an array",
          value: card.classifications,
        });
      }
    }
    expect(violations).toEqual([]);
  });

  it("normalized cards records all satisfy structural invariants", () => {
    const violations: Violation[] = [];
    for (const card of cards) {
      const slug = card.slug ?? "<missing slug>";
      assertString(slug, "id", card.id, violations, { regex: UUID_REGEX });
      assertExternalId(slug, "externalId", card.externalId, violations);
      assertString(slug, "slug", card.slug, violations, { regex: SLUG_REGEX });
      assertString(slug, "name", card.name, violations);
      assertString(slug, "displayName", card.displayName, violations);
      assertEnum(slug, "set.code", card.set?.code, KNOWN_SET_CODE_VALUES, violations);
      assertEnum(slug, "color", card.color, KNOWN_COLORS, violations);
      assertEnum(slug, "type", card.type, KNOWN_CARD_TYPES, violations);
      assertEnum(slug, "legality", card.legality, KNOWN_LEGALITIES, violations);
      assertString(slug, "imageUrl", card.imageUrl, violations, { startsWith: "https://" });
      assertString(slug, "sourceImageUrl", card.sourceImageUrl, violations, {
        startsWith: "https://",
      });
      assertString(slug, "printNumber", card.printNumber, violations);
      assertString(slug, "artist", card.artist, violations);
      assertNonNegativeInt(slug, "ram", card.ram, violations);
      // cost/power constraints vary by card type (programs always have power: null,
      // legends may have null cost/power). Trust the discriminated-union type for
      // type-correctness; just verify shape here.
      if (card.cost !== undefined && card.cost !== null) {
        assertNonNegativeInt(slug, "cost", card.cost, violations);
      }
      if (card.power !== undefined && card.power !== null) {
        assertNonNegativeInt(slug, "power", card.power, violations);
      }
      if (!Array.isArray(card.classifications)) {
        violations.push({
          cardSlug: slug,
          field: "classifications",
          reason: "not an array",
          value: card.classifications,
        });
      }
      if (!Array.isArray(card.keywords)) {
        violations.push({
          cardSlug: slug,
          field: "keywords",
          reason: "not an array",
          value: card.keywords,
        });
      }
      if (!Array.isArray(card.timingTriggers)) {
        violations.push({
          cardSlug: slug,
          field: "timingTriggers",
          reason: "not an array",
          value: card.timingTriggers,
        });
      }
    }
    expect(violations).toEqual([]);
  });

  it("structuredCards all satisfy structural invariants and have an abilities array", () => {
    const violations: Violation[] = [];
    for (const card of structuredCards) {
      const slug = card.slug ?? "<missing slug>";
      assertString(slug, "id", card.id, violations, { regex: UUID_REGEX });
      assertExternalId(slug, "externalId", card.externalId, violations);
      assertString(slug, "slug", card.slug, violations, { regex: SLUG_REGEX });
      assertEnum(slug, "set.code", card.set?.code, KNOWN_SET_CODE_VALUES, violations);
      assertEnum(slug, "color", card.color, KNOWN_COLORS, violations);
      assertEnum(slug, "type", card.type, KNOWN_CARD_TYPES, violations);
      if (!Array.isArray(card.abilities)) {
        violations.push({
          cardSlug: slug,
          field: "abilities",
          reason: "not an array",
          value: card.abilities,
        });
      }
      if (!Array.isArray(card.reminderText)) {
        violations.push({
          cardSlug: slug,
          field: "reminderText",
          reason: "not an array",
          value: card.reminderText,
        });
      }
    }
    expect(violations).toEqual([]);
  });

  it("rawCards and cards agree on primary keys (set, id, slug, externalId)", () => {
    const violations: Array<{ key?: string; slug?: string; reason: string }> = [];
    expect(rawCards.length).toBe(cards.length);
    const rawBySetAndSlug = new Map(rawCards.map((c) => [`${c.set.code}:${c.slug}`, c]));
    for (const card of cards) {
      const key = `${card.set.code}:${card.slug}`;
      const raw = rawBySetAndSlug.get(key);
      if (!raw) {
        violations.push({
          slug: card.slug,
          reason: `no matching rawCard for ${key}`,
        });
        continue;
      }
      if (raw.id !== card.id) {
        violations.push({ key, reason: `id mismatch (${raw.id} vs ${card.id})` });
      }
      if (raw.external_id !== card.externalId) {
        violations.push({
          key,
          reason: `externalId mismatch (${raw.external_id} vs ${card.externalId})`,
        });
      }
    }
    expect(violations).toEqual([]);
  });
});
